import sys
from collections import deque

def min_days(N, K, v):
    # Bipartite graph: left node i (0..N-1) can connect to right node j
    # if i < j and |v[i]-v[j]| >= K  (j can directly follow i on the same day)
    adj = [[] for _ in range(N)]
    for i in range(N):
        for j in range(i + 1, N):
            if abs(v[i] - v[j]) >= K:
                adj[i].append(j)

    # Hopcroft-Karp maximum bipartite matching
    INF = float('inf')
    matchL = [-1] * N  # left i matched to right matchL[i]
    matchR = [-1] * N  # right j matched to left matchR[j]
    dist = [0] * N

    def bfs():
        q = deque()
        for i in range(N):
            if matchL[i] == -1:
                dist[i] = 0
                q.append(i)
            else:
                dist[i] = INF
        found = False
        while q:
            i = q.popleft()
            for j in adj[i]:
                pi = matchR[j]
                if pi == -1:
                    found = True
                elif dist[pi] == INF:
                    dist[pi] = dist[i] + 1
                    q.append(pi)
        return found

    def dfs(i):
        for j in adj[i]:
            pi = matchR[j]
            if pi == -1 or (dist[pi] == dist[i] + 1 and dfs(pi)):
                matchL[i] = j
                matchR[j] = i
                return True
        dist[i] = INF
        return False

    matching = 0
    while bfs():
        for i in range(N):
            if matchL[i] == -1 and dfs(i):
                matching += 1

    return N - matching


def main():
    data = sys.stdin.read().split()
    idx = 0
    T = int(data[idx]); idx += 1
    out = []
    for _ in range(T):
        N = int(data[idx]); K = int(data[idx + 1]); idx += 2
        v = [int(data[idx + t]) for t in range(N)]; idx += N
        out.append(str(min_days(N, K, v)))
    print('\n'.join(out))


if __name__ == "__main__":
    main()
